
<template>
  <section v-if="authEnabled && !token" class="admin-login-page">
    <form class="admin-login-card" @submit.prevent="doLogin"><h1>若依管理后台</h1><p>跨境选品系统 · admin / admin</p><label>账号<input v-model="login.username" /></label><label>密码<input type="password" v-model="login.password" /></label><button>登录</button><p v-if="message" class="notice">{{ message }}</p></form>
  </section>
  <section v-else class="ruoyi-layout">
