    <main class="ruoyi-main">
      <header class="ruoyi-topbar"><div><strong>{{ activeTitle }}</strong><small>首页 / {{ activeTitle }}</small></div><div class="ruoyi-user"><select v-model="currentTenant"><option value="*">全部租户</option><option v-for="t in tenants" :key="t.tenantId" :value="t.tenantId">{{ t.tenantName }}</option></select><span>{{ profile?.nickname }}({{ profile?.tenantId }})</span><button class="ghost" @click="logout">退出</button></div></header>
      <div class="ruoyi-tags"><span>首页</span><span>{{ activeTitle }}</span></div>
      <section v-if="activeMenu==='dashboard'" class="admin-panel"><h2>工作台</h2><div class="admin-kpis"><article><span>租户</span><b>{{ tenants.length }}</b></article><article><span>用户</span><b>{{ users.length }}</b></article><article><span>角色</span><b>{{ roles.length }}</b></article><article><span>菜单</span><b>{{ flatMenus.length }}</b></article></div><p class="muted">核心若依管理闭环已启用：租户、用户、角色、菜单、字典、参数、日志、选品配置和报表管理。</p></section>

      <CrudPage v-if="activeMenu==='users'" title="用户管理" :rows="users" :columns="userColumns" :fields="userFields" :empty="emptyUser" @save="saveUser" @delete="deleteUser" />
      <section v-if="activeMenu==='roles'" class="admin-panel"><div class="crud-head"><h2>角色管理</h2><button @click="editingRole={id:0,tenantId:'default',roleKey:'',roleName:'',status:'enabled',menuKeys:[],remark:''}">新增</button></div><AdminDataTable :rows="roles" :columns="roleColumns" actions @edit="editingRole={...$event,menuKeys:[...($event.menuKeys||[])]}" @delete="deleteRole"/><AdminModalForm v-if="editingRole" title="角色表单" :model="editingRole" :fields="roleFields" @save="saveRole" @cancel="editingRole=null"><template #default="{draft}"><label>菜单权限<div class="check-grid"><label v-for="m in flatMenus" :key="m.menuKey"><input type="checkbox" :value="m.menuKey" v-model="draft.menuKeys"/>{{ m.title }}</label></div></label></template></AdminModalForm></section>
