      <section v-if="activeMenu==='dailyReports'" class="admin-panel"><h2>日报记录</h2><AdminDataTable :rows="reports" :columns="reportColumns"/></section>
      <section v-if="activeMenu==='productPool'" class="admin-panel"><h2>商品池</h2><AdminDataTable :rows="productPool" :columns="productColumns"/></section>
      <p v-if="message" class="notice floating-notice">{{ message }}</p>
    </main>
  </section>
</template>

<script setup>
