const profile=ref(null), menus=ref([]), users=ref([]), roles=ref([]), tenants=ref([]), dictTypes=ref([]), dictData=ref([]), configs=ref([]), operLogs=ref([]), loginLogs=ref([]), markets=ref([]), categories=ref([]), settings=ref(null), sources=ref([]), reports=ref([]);
