function flatten(items){return items.flatMap(m=>[m,...(m.children?flatten(m.children):[])]);} function removeTenant(items){return (items||[]).filter(m=>m.menuKey!=='tenants').map(m=>({...m,children:removeTenant(m.children)}));} function tenantParam(){return currentTenant.value==='*'?'*':currentTenant.value;} async function adminApi(path,o={}){return api(path,{...o,headers:{...(o.headers||{}),Authorization:`Bearer ${token.value}`}})}
async function doLogin(){try{const r=await api('/admin/login',{method:'POST',body:JSON.stringify(login)});token.value=r.token;localStorage.setItem('adminToken',r.token);await loadAll();}catch(e){message.value='账号或密码错误';}}
function logout(){localStorage.removeItem('adminToken'); token.value='';} function selectMenu(m){if(m.component!=='Layout')activeMenu.value=m.menuKey;}
async function loadAll(){const status=await api('/admin/auth/status'); authEnabled.value=status.enabled; if(status.enabled&&!token.value)return; const [p,m,t,u,r,dt,dd,cfg,ol,ll,ma,ca,s,ds,rs]=await Promise.all([adminApi('/admin/profile'),adminApi('/admin/menus'),adminApi('/admin/tenants'),adminApi('/admin/users'),adminApi('/admin/roles'),adminApi('/admin/dict-types'),adminApi('/admin/dict-data'),adminApi('/admin/configs'),adminApi('/admin/oper-logs'),adminApi('/admin/login-logs'),adminApi('/admin/markets'),adminApi('/admin/categories'),adminApi('/admin/settings'),api('/datasources'),api('/reports')]); profile.value=p; menus.value=removeTenant(m); tenants.value=t; users.value=u; roles.value=r; dictTypes.value=dt; dictData.value=dd; configs.value=cfg; operLogs.value=ol; loginLogs.value=ll; markets.value=ma; categories.value=ca; settings.value=s; sources.value=ds; reports.value=rs;}
watch(currentTenant, async()=>{ if(!authEnabled.value || token.value){ users.value=await adminApi('/admin/users?tenantId='+tenantParam()); roles.value=await adminApi('/admin/roles?tenantId='+tenantParam()); markets.value=await adminApi('/admin/markets?tenantId='+tenantParam()); categories.value=await adminApi('/admin/categories?tenantId='+tenantParam()); }});
async function saveSettings(v){settings.value=await adminApi('/admin/settings',{method:'PUT',body:JSON.stringify(v)}); message.value='配置已保存';}
