async function saveTenant(row){await adminApi(row.id?`/admin/tenants/${row.id}`:'/admin/tenants',{method:row.id?'PUT':'POST',body:JSON.stringify(row)});tenants.value=await adminApi('/admin/tenants');} async function deleteTenant(row){await adminApi(`/admin/tenants/${row.id}`,{method:'DELETE'});tenants.value=await adminApi('/admin/tenants');}
async function saveUser(row){await adminApi(row.id?`/admin/users/${row.id}`:'/admin/users',{method:row.id?'PUT':'POST',body:JSON.stringify(row)});users.value=await adminApi('/admin/users?tenantId='+tenantParam());} async function deleteUser(row){await adminApi(`/admin/users/${row.id}`,{method:'DELETE'});users.value=await adminApi('/admin/users?tenantId='+tenantParam());}
async function saveRole(row){await adminApi(row.id?`/admin/roles/${row.id}`:'/admin/roles',{method:row.id?'PUT':'POST',body:JSON.stringify(row)});editingRole.value=null;roles.value=await adminApi('/admin/roles?tenantId='+tenantParam());} async function deleteRole(row){await adminApi(`/admin/roles/${row.id}`,{method:'DELETE'});roles.value=await adminApi('/admin/roles?tenantId='+tenantParam());}
