async function saveDictType(row){await adminApi(row.id?`/admin/dict-types/${row.id}`:'/admin/dict-types',{method:row.id?'PUT':'POST',body:JSON.stringify(row)});dictTypes.value=await adminApi('/admin/dict-types?tenantId='+tenantParam());} async function deleteDictType(row){await adminApi(`/admin/dict-types/${row.id}`,{method:'DELETE'});dictTypes.value=await adminApi('/admin/dict-types?tenantId='+tenantParam());}
