async function saveConfig(row){await adminApi(row.id?`/admin/configs/${row.id}`:'/admin/configs',{method:row.id?'PUT':'POST',body:JSON.stringify(row)});configs.value=await adminApi('/admin/configs?tenantId='+tenantParam());} async function deleteConfig(row){await adminApi(`/admin/configs/${row.id}`,{method:'DELETE'});configs.value=await adminApi('/admin/configs?tenantId='+tenantParam());}
async function saveMarket(row){await adminApi(row.id?`/admin/markets/${row.id}`:'/admin/markets',{method:row.id?'PUT':'POST',body:JSON.stringify(row)});markets.value=await adminApi('/admin/markets?tenantId='+tenantParam());}
