const marketColumns=[['tenantId','租户'],['marketKey','标识'],['marketName','名称'],['region','区域'],['enabled','启用'],['note','说明']].map(([key,label])=>({key,label})); const categoryColumns=[['tenantId','租户'],['categoryName','品类'],['marketKey','市场'],['enabled','启用'],['keywords','关键词']].map(([key,label])=>({key,label})); const operLogColumns=[['createdAt','时间'],['tenantId','租户'],['username','用户'],['module','模块'],['action','操作'],['status','状态'],['message','消息']].map(([key,label])=>({key,label})); const loginLogColumns=[['createdAt','时间'],['tenantId','租户'],['username','用户'],['ipaddr','IP'],['status','状态'],['message','消息']].map(([key,label])=>({key,label})); const reportColumns=[['reportDate','日期'],['title','标题'],['sourceMode','数据源'],['summary','摘要']].map(([key,label])=>({key,label})); const productColumns=[['rank','排名'],['productNameCn','商品'],['category','品类'],['heatScore','热度'],['estimatedProfitCny','利润']].map(([key,label])=>({key,label}));
const tenantFields=computed(()=>[{key:'tenantId',label:'租户标识'},{key:'tenantName',label:'租户名称'},{key:'contactUser',label:'联系人'},{key:'contactPhone',label:'联系电话'},{key:'packageName',label:'套餐'},{key:'status',label:'状态',type:'select',options:statusOpts},{key:'remark',label:'备注'}]); const userFields=computed(()=>[{key:'tenantId',label:'租户',type:'select',options:tenantOpts.value},{key:'username',label:'用户名'},{key:'password',label:'密码'},{key:'nickname',label:'昵称'},{key:'roleKey',label:'角色',type:'select',options:roleOpts.value},{key:'status',label:'状态',type:'select',options:statusOpts},{key:'email',label:'邮箱'},{key:'phone',label:'手机'}]); const roleFields=computed(()=>[{key:'tenantId',label:'租户',type:'select',options:tenantOpts.value},{key:'roleKey',label:'角色标识'},{key:'roleName',label:'角色名称'},{key:'status',label:'状态',type:'select',options:statusOpts},{key:'remark',label:'备注'}]); const menuFields=computed(()=>[{key:'parentId',label:'父级菜单',type:'select',options:menuOpts.value},{key:'menuKey',label:'菜单标识'},{key:'title',label:'菜单名称'},{key:'icon',label:'图标'},{key:'path',label:'路由'},{key:'component',label:'组件'},{key:'permission',label:'权限标识'},{key:'sortOrder',label:'排序',type:'number'},{key:'status',label:'状态',type:'select',options:statusOpts}]);
